mapper.select:
SELECT id, title, content, level, publish_mode, scheduled_at, popup_enabled, valid_from, valid_to, target_type, status, published_at, remark, created_by, updated_by, created_at, updated_at, is_deleted, deleted_category, deleted_at, deleted_by FROM jq_sys_notice WHERE is_deleted = 1
AND deleted_category = #{category}
ORDER BY deleted_at DESC, id DESC
